mapper.select:
SELECT * FROM (
	SELECT ROWNUM AS rnum, A.* FROM (
		SELECT notice_id, admin_id, category, title,
			   view_count, is_top, created_at
		FROM NOTICE


				title LIKE '%'||#{sc.keyword}||'%'


				AND category = #{sc.category}


				AND status = #{sc.status}


		ORDER BY is_top DESC, created_at DESC
	) A
)
WHERE rnum BETWEEN #{paging.startRow} AND #{paging.endRow}

SELECT COUNT(*) FROM NOTICE


		title LIKE CONCAT('%', #{sc.keyword}, '%')


		AND category = #{sc.category}


		AND status = #{sc.status}
